// MARK: - Offline review fallback
// The live Places path returns real Google reviews. This baked snapshot has none,
// so we attach a rotating pool of sample reviews to any contractor missing them —
// guarantees the redesigned scrollable review list is populated when offline.
// ─────────────────────────────────────────────────────────────────────────────

private let sampleReviewPool: [Review] = [
    Review(author: "Jacob Washington", authorPhotoURL: nil, rating: 5,
           text: "Showed up on time, diagnosed the problem in minutes and fixed it cleanly. Honest pricing — no upsell.", relativeTime: "2 weeks ago"),
    Review(author: "Maria Chen", authorPhotoURL: nil, rating: 5,
           text: "Same-day service and very professional. Left the place spotless when they were done.", relativeTime: "3 weeks ago"),
    Review(author: "Derek Simmons", authorPhotoURL: nil, rating: 4,
           text: "Fair quote and solid work. Took a little longer than estimated but the result is great.", relativeTime: "1 month ago"),
    Review(author: "Linda Park", authorPhotoURL: nil, rating: 5,
           text: "Explained every step before starting and walked me through it afterward. Highly recommend.", relativeTime: "1 month ago"),
    Review(author: "Tom Nguyen", authorPhotoURL: nil, rating: 5,
           text: "Emergency call late at night — they answered and had someone out within the hour. Lifesavers.", relativeTime: "2 months ago"),
    Review(author: "Sandra Okafor", authorPhotoURL: nil, rating: 4,
           text: "Friendly crew and reasonable rates. My go-to from now on.", relativeTime: "2 months ago"),
    Review(author: "Kevin Marsh", authorPhotoURL: nil, rating: 5,
           text: "Handled a tricky job two other companies couldn't. Worth every penny.", relativeTime: "3 months ago"),
    Review(author: "Amy Torres", authorPhotoURL: nil, rating: 5,
           text: "Great communication from booking to finish. Sent a photo update when the job was done.", relativeTime: "3 months ago"),
    Review(author: "Brian Kowalski", authorPhotoURL: nil, rating: 4,
           text: "Honest and efficient. Didn't try to sell me anything I didn't need.", relativeTime: "4 months ago"),
    Review(author: "Jasmine Reid", authorPhotoURL: nil, rating: 5,
           text: "Quick, courteous and reasonably priced. The work has held up perfectly.", relativeTime: "5 months ago"),
]

/// Contractors with a rotating slice of sample reviews filled in where missing.
let mockContractors: [Contractor] = rawMockContractors.enumerated().map { index, contractor in
    guard contractor.reviews.isEmpty else { return contractor }
    var c = contractor
    // Rotate the starting point so different cards show different lead reviews.
    let start = index % sampleReviewPool.count
    let rotated = Array(sampleReviewPool[start...] + sampleReviewPool[..<start])
    // Never show more sample reviews than the business's total count, and cap at
    // 5 (Google's max). Keeps "N reviews" consistent with the rows displayed.
    let count = min(5, max(0, contractor.reviewCount), 3 + index % 3)
    c.reviews = Array(rotated.prefix(count))
    return c
}
